#include <bits/stdc++.h>
using namespace std;
int main(){
    int a,b;
    cin>>a>>b;
    long long c[a],d[b];
    for(int i=0;i<a;i++){
		cin>>c[i];
	}
	for(int i=0;i<b;i++){
		cin>>d[i];
	}
	sort(c,c+a);
	sort(d,d+b);
	int ans=0;
	for(int i=0;i<a;i++){
		int l=0,r=b-1,mid;
		while(l<=r){
			mid=(l+r)/2;
			if(d[mid]<c[i]){
				l=mid+1;
			}
			else if(d[mid]>c[i]){
				r=mid-1;
			}
			else{
				break;
			}
		}
		if(d[mid]==c[i]){
			ans++;
		}
	}
	cout<<ans;
    return 0;
}
